  ('colonel-7fec267e-moex-00144', 'colonel-7fec267e', 'colonel-7fec267e-moex-112-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '關於行政協助之敘述，下列何者錯誤？', '["行政機關執行職務時，有因人員、設備不足等事實上之原因，不能獨自 執行職務者，得向無隸屬關係之其他機關請求協助", "行政協助之請求，除緊急情形外，應以書面為之", "被請求機關得向請求協助機關要求負擔行政協助所需費用，並由請求協 助機關及被請求機關以協議定之；協議不成時，依司法救濟程序辦理之", "行政機關為發揮共同一體之行政機能，應於其權限範圍內互相協助"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00145', 'colonel-7fec267e', 'colonel-7fec267e-moex-112-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '關於行政契約之執行，下列敘述何者正確？', '["行政契約本身即得作為行政強制執行之執行名義", "人民不履行契約義務時，行政機關原則上得作成行政處分命其履行；不 履行時，得為行政執行", "行政契約如有自願接受執行之約定，債務人不履行時，債權人無須藉由 行政訴訟取得執行名義", "行政機關不履行契約義務時，如有自願接受執行之約定，得準用行政執 行法為執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00146', 'colonel-7fec267e', 'colonel-7fec267e-moex-112-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'single_choice', '依司法院釋字第785號解釋意旨，下列敘述何者錯誤？', '["公務人員保障法所規定之申訴與再申訴制度並不違憲", "依法提起行政訴訟之權利不應因公務人員之身分而有異", "對公務人員之影響，如屬顯然輕微之干預，即難謂構成權利之侵害", "服勤、休假之頻率與休息最低時數，屬工作條件，尚無涉公務人員服公 職權與健康權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
